mapper.sql:
AND a.confirmyn = #{confirm_yn}
AND ( -- 1. 받은날짜가 기준 (a.source = 'RECEIVING' AND UPPER(a.factory) = UPPER(
#{moveFactory}
'SALTILLO'
)
AND UPPER(a.storage) LIKE UPPER('%${moveStorage}%') AND a.indate BETWEEN #{fromDate} AND #{toDate})
OR -- 2. 받은 건에 대응하는 보내기 (a.source = 'SENDING' AND UPPER(a.factory) = UPPER(
#{factory}
'PUEBLA'
) AND a.barcode IN ( SELECT r.barcode FROM t_wms_factorymove r WHERE r.useyn='Y' AND r.source='RECEIVING' AND UPPER(r.factory) = UPPER(
#{moveFactory}
'SALTILLO'
) AND UPPER(r.storage) LIKE UPPER('%${moveStorage}%') AND r.indate BETWEEN #{fromDate} AND #{toDate} ))
OR -- 3. 보냈지만 아직 안 받은 것 (a.source = 'SENDING' AND UPPER(a.factory) = UPPER(
#{factory}
'PUEBLA'
)
AND a.indate BETWEEN #{fromDate} AND #{toDate} AND NOT EXISTS ( SELECT 1 FROM t_wms_factorymove r WHERE r.useyn='Y' AND r.source='RECEIVING' AND r.barcode = a.barcode )) )
AND UPPER(a.itemcode) LIKE '%' || UPPER(#{itemcode}) || '%'
AND UPPER(REPLACE(b.itemname, ' ', '')) LIKE '%' || UPPER(REPLACE(#{itemname}, ' ', '')) || '%'

( kind <> 'INVENTORY'
AND UPPER(storage) = UPPER(#{storage})
AND UPPER(storage) = 'MATERIAL'
AND sdate BETWEEN #{fromDate} AND #{toDate}
AND UPPER(itemcode) LIKE '%' || UPPER(#{itemcode}) || '%'
) or ( kind = 'INVENTORY'
AND UPPER(storage) = UPPER(#{storage})
AND UPPER(storage) = 'MATERIAL'
AND sdate = #{fromDate}
AND UPPER(itemcode) LIKE '%' || UPPER(#{itemcode}) || '%'
)

choose.when:
           AND has_wms = 0


	            AND arrival_date >= #{searchParams.fromDate}


	            AND arrival_date <= #{searchParams.toDate}

choose.otherwise:
		        	AND (
				        /* 미도착 : 날짜 무시 */
				        has_wms = 1

				        OR

				        /* 배송완료 : 날짜 조건 적용 */
				        (has_wms = 0


				            AND arrival_date >= #{searchParams.fromDate}


				            AND arrival_date <= #{searchParams.toDate}

			        	)
  					)

choose.when:
		            AND NOT EXISTS (
					    SELECT 1
					    FROM t_mex_scm_invoice@ptlink x
					    WHERE x.invoice_no = i2.invoice_no
					      AND x.mes_key IS NOT NULL
					)

                        AND i2.arrival_date >= #{searchParams.fromDate}


                        AND i2.arrival_date <= #{searchParams.toDate}

choose.otherwise:
		        	AND (
				        /* 미도착 : 날짜 무시 */
				        EXISTS (
				            SELECT 1
				            FROM t_mex_scm_invoice@ptlink x
				            WHERE x.invoice_no = i2.invoice_no
				              AND TRIM(x.mes_key) IS NOT NULL
				        )

				        OR

				        /* 배송완료 : 날짜 조건 적용 */
				        (
				            NOT EXISTS (
				                SELECT 1
				                FROM t_mex_scm_invoice@ptlink x
				                WHERE x.invoice_no = i2.invoice_no
				                  AND TRIM(x.mes_key) IS NOT NULL
				            )


					            AND i2.arrival_date >= #{searchParams.fromDate}


					            AND i2.arrival_date <= #{searchParams.toDate}

			        	)
   					)

sql.if:
        AND (
            -- 1. 받은날짜가 기준
            (a.source = 'RECEIVING'
             AND UPPER(TRIM(a.factory)) = UPPER(TRIM(


                     #{searchParams.moveFactory}


                     'SALTILLO'


             ))



					AND UPPER(TRIM(a.storage)) = 'MATERIAL'




				        AND REPLACE(UPPER(TRIM(a.storage)), ' ', '') IN ('MATERIAL','SIDESEAT','OUTSIDE')




				        AND UPPER(TRIM(a.storage)) = UPPER(TRIM(#{searchParams.moveStorage}))




                 AND a.sdate >= #{searchParams.fromDate}


                 AND a.sdate <= #{searchParams.toDate}

            )

            OR

            -- 2. 받은 건에 대응하는 보내기
            (a.source = 'SENDING'
             AND UPPER(TRIM(a.factory)) = UPPER(TRIM(


                     #{searchParams.factory}


                     'PUEBLA'


             ))
             AND a.barcode IN (
                 SELECT r.barcode
                 FROM t_wms_factorymove r
                 WHERE r.useyn='Y'
                   AND r.source='RECEIVING'
                   AND UPPER(TRIM(r.factory)) = UPPER(TRIM(


                           #{searchParams.moveFactory}


                           'SALTILLO'


                   ))



				        AND UPPER(TRIM(a.storage)) = 'MATERIAL'




				        AND REPLACE(UPPER(TRIM(a.storage)), ' ', '') IN ('MATERIAL','SIDESEAT','OUTSIDE')




				        AND UPPER(TRIM(a.storage)) = UPPER(TRIM(#{searchParams.moveStorage}))




                       AND r.sdate >= #{searchParams.fromDate}


                       AND r.sdate <= #{searchParams.toDate}

             ))

            OR

            -- 3. 보냈지만 아직 안 받은 것
            (a.source = 'SENDING'
             AND UPPER(TRIM(a.factory)) = UPPER(TRIM(


                     #{searchParams.factory}


                     'PUEBLA'


             ))


                 AND a.sdate >= #{searchParams.fromDate}


                 AND a.sdate <= #{searchParams.toDate}

             AND NOT EXISTS (
                 SELECT 1
                 FROM t_wms_factorymove r
                 WHERE r.useyn='Y'
                   AND r.source='RECEIVING'
                   AND r.barcode = a.barcode
             ))
        )



            AND UPPER(TRIM(a.itemcode)) LIKE '%' || UPPER(TRIM(#{searchParams.itemcode})) || '%'


            AND UPPER(TRIM(b.itemname)) LIKE '%' || UPPER(TRIM(#{searchParams.itemname})) || '%'


            AND UPPER(TRIM(c.subname_ch)) LIKE '%' || UPPER(TRIM(#{searchParams.car})) || '%'


            AND UPPER(TRIM(a.barcode)) LIKE '%' || UPPER(TRIM(#{searchParams.barcode})) || '%'



  AND a.indate >= #{searchParams.fromDate}


  AND a.indate <= #{searchParams.toDate}



AND UPPER(TRIM(a.factory)) = UPPER(TRIM(


      #{searchParams.factory}


      'SALTILLO'


))




    AND UPPER(TRIM(a.storage)) = 'MATERIAL'



    AND REPLACE(UPPER(TRIM(a.storage)), ' ', '') IN ('MATERIAL','SIDESEAT','OUTSIDE')



    AND UPPER(TRIM(a.storage)) = UPPER(TRIM(#{searchParams.storage}))





  AND UPPER(TRIM(a.wccode)) LIKE '%' || UPPER(TRIM(#{searchParams.workCenter})) || '%'

AND (
	-- 1. 받은날짜가 기준
	(
		a.source = 'RECEIVING'

			AND a.factory = #{searchParams.factory}


			AND a.storage2 = #{searchParams.toStorage}


			AND a.sdate >= #{searchParams.fromDate}


			AND a.sdate <= #{searchParams.toDate}

	)
	OR
	-- 2. 받은 건에 대응하는 보내기
	(
		a.source = 'SENDING'

			AND a.storage1 = #{searchParams.fromStorage}

		AND a.barcode IN (
			SELECT r.barcode
			FROM t_wms_stockmove r
			WHERE r.useyn='Y'
			AND r.source='RECEIVING'

				AND r.factory = #{searchParams.factory}


				AND a.storage2 = #{searchParams.toStorage}


				AND r.sdate >= #{searchParams.fromDate}


				AND r.sdate <= #{searchParams.toDate}

		)
	)
	OR
	-- 3. 보냈지만 아직 안 받은 것
	(
		a.source = 'SENDING'

			AND a.storage1 = #{searchParams.fromStorage}


			AND a.sdate >= #{searchParams.fromDate}


			AND a.sdate <= #{searchParams.toDate}

		AND NOT EXISTS (
			SELECT 1
			FROM t_wms_stockmove r
			WHERE r.useyn='Y'
			AND r.source='RECEIVING'
			AND r.barcode = a.barcode
		)
	)
)


	AND UPPER(TRIM(a.itemcode)) LIKE '%' || UPPER(TRIM(#{searchParams.itemcode})) || '%'


	AND UPPER(TRIM(b.spec)) LIKE '%' || UPPER(TRIM(#{searchParams.oitemcode})) || '%'


	AND UPPER(TRIM(b.itemname)) LIKE '%' || UPPER(TRIM(#{searchParams.itemname})) || '%'


	AND UPPER(TRIM(c.subname_ch)) LIKE '%' || UPPER(TRIM(#{searchParams.car})) || '%'


	AND UPPER(TRIM(a.barcode)) LIKE '%' || UPPER(TRIM(#{searchParams.barcode})) || '%'
